import React, { useState } from 'react';

const MessageRenderer = ({ content, type }) => {
  const [copiedCode, setCopiedCode] = useState('');

  const copyToClipboard = (text, id) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopiedCode(id);
      setTimeout(() => setCopiedCode(''), 2000);
    });
  };

  const parseContent = (text) => {
    const parts = [];
    let currentIndex = 0;

    // Regex patterns for different content types
    const codeBlockRegex = /``````/g;
    const inlineCodeRegex = /`([^`]+)`/g;
    const mathRegex = /\$\$?([\s\S]*?)\$\$?/g;
    const boldRegex = /\*\*(.*?)\*\*/g;
    const italicRegex = /\*(.*?)\*/g;
    const linkRegex = /\[([^\]]+)\]\(([^)]+)\)/g;
    const listRegex = /^[-*+]\s+(.+)$/gm;
    const numberedListRegex = /^\d+\.\s+(.+)$/gm;

    let match;

    // Find all code blocks first
    const codeBlocks = [];
    while ((match = codeBlockRegex.exec(text)) !== null) {
      codeBlocks.push({
        type: 'code',
        start: match.index,
        end: match.index + match[0].length,
        language: match[1] || 'text',
        content: match[2].trim(),
        fullMatch: match[0]
      });
    }

    // Find math expressions
    mathRegex.lastIndex = 0;
    const mathBlocks = [];
    while ((match = mathRegex.exec(text)) !== null) {
      // Skip if inside code block
      const inCodeBlock = codeBlocks.some(cb => 
        match.index >= cb.start && match.index < cb.end
      );
      if (!inCodeBlock) {
        mathBlocks.push({
          type: 'math',
          start: match.index,
          end: match.index + match[0].length,
          content: match[1].trim(),
          fullMatch: match[0]
        });
      }
    }

    // Combine and sort all blocks
    const allBlocks = [...codeBlocks, ...mathBlocks].sort((a, b) => a.start - b.start);

    // Process text with blocks
    allBlocks.forEach((block, index) => {
      // Add text before block
      if (currentIndex < block.start) {
        const textContent = text.slice(currentIndex, block.start);
        if (textContent.trim()) {
          parts.push({
            type: 'text',
            content: textContent,
            id: `text-${index}`
          });
        }
      }

      // Add the block
      parts.push({
        ...block,
        id: `block-${index}`
      });

      currentIndex = block.end;
    });

    // Add remaining text
    if (currentIndex < text.length) {
      const remainingText = text.slice(currentIndex);
      if (remainingText.trim()) {
        parts.push({
          type: 'text',
          content: remainingText,
          id: 'text-final'
        });
      }
    }

    return parts.length > 0 ? parts : [{ type: 'text', content: text, id: 'text-only' }];
  };

  const formatText = (text) => {
    return text
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/`([^`]+)`/g, '<code class="inline-code">$1</code>')
      .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>')
      .replace(/^[-*+]\s+(.+)$/gm, '<li>$1</li>')
      .replace(/^\d+\.\s+(.+)$/gm, '<li>$1</li>')
      .replace(/\n/g, '<br>');
  };

  const renderCodeBlock = (content, language, id) => (
    <div className="code-block" key={id}>
      <div className="code-header">
        <span>{language.toUpperCase()}</span>
        <button 
          className="copy-code-btn"
          onClick={() => copyToClipboard(content, id)}
        >
          {copiedCode === id ? '✓ Copied!' : '📋 Copy'}
        </button>
      </div>
      <pre>
        <code>{content}</code>
      </pre>
    </div>
  );

  const renderMathExpression = (content, id) => (
    <div className="math-expression" key={id}>
      <div className="math-content">
        {content}
      </div>
    </div>
  );

  const renderTextContent = (content, id) => (
    <div 
      className="text-content" 
      key={id}
      dangerouslySetInnerHTML={{ 
        __html: formatText(content) 
      }} 
    />
  );

  const parsedContent = parseContent(content);

  return (
    <div className="message-renderer">
      {parsedContent.map(part => {
        switch (part.type) {
          case 'code':
            return renderCodeBlock(part.content, part.language, part.id);
          case 'math':
            return renderMathExpression(part.content, part.id);
          case 'text':
          default:
            return renderTextContent(part.content, part.id);
        }
      })}
    </div>
  );
};

export default MessageRenderer;
